    #[test]
    fn wrap_command_with_optional_timeout_adds_kill_after_grace() {
        let wrapped = wrap_command_with_optional_timeout(
            "codex".to_string(),
            vec!["exec".to_string()],
            Some(5),
        );

        assert_eq!(wrapped.command, "timeout");
        assert_eq!(
            wrapped.args,
            vec![
